(window.webpackJsonp=window.webpackJsonp||[]).push([[334],{961:function(n,e){n.exports="\x3c!--\ntitle: 01-Jquery入门\nsort: \n--\x3e \n\n## 选择器\n\n```js\nvar getOne = $('demo')\n\n// 添加css\ngetOne.css('color', 'white')\n// 获得下面的p标签\ngetOne.find('p')\n// 获取父类\ngetOne.parent().css('color', 'white')\n// 含有yellow类的\ngetOne.filter('.yellow').css('background', 'yellow')\n\n// 批量添加\ngetOne.css({\n    color: 'red',\n    'background-color': 'gray',\n    border: '2px solid black'\n})\n// 添加删除类名\ngetOne.addClass('demo')\n\t.removeClass('demo')\n// 判断是否含有类名\njquery_test.hasClass('demo');\n\n// 展示、隐藏\njquery_test.show();\njquery_test.hide();\n// 缓出 缓入\njquery_test.fadeIn(500);\njquery_test.fadeOut(500);\n// 滑入 滑出\njquery_test.slideUp(500)\njquery_test.slideDown(500)\n\n// 内容\n    jquery_test.text()\njquery_test.html()\njquery_test.append('<p>test</p>')\njquery_test.prepend('<p>test</p>')\njquery_test.remove()\n```\n\n> 广告版\n\n```js\n<h1 id=\"board\">成人用品 二楼右拐</h1>\n\nvar board = $('#board');\nfunction toggle(){\n  \t// 判断是否active\n    if(board.hasClass('active')){\n        board.removeClass('active');\n    } else {\n        board.addClass('active');\n    }\n}\n// 200ms执行一次\nsetInterval(toggle,200);\n```\n\n## 事件\n\n```js\nvar card = $('#card');\nvar cardTrigger = $('#card-trigger');\n\n// 触发\ncardTrigger.click(\n  () => {\n    // 判断是否展示\n    if (card.is(':visible')) {\n      card.slideUp()\n    } else {\n      card.slideDown()\n    }\n  }\n)\n// 鼠标移动则active\ncard.on('mouseenter',\n  () => {\n    card.addClass('active');\n  }\n)\n\ncard.on('mouseleave',\n  () => {\n    card.removeClass('active');\n  }\n)\n\n// 更简单的方法-隐藏或显示元素\n// card.toggle();\n```\n\n## 属性操作\n\n```js\n$('#a')\n  .attr('href', 'https://baidu.com');\n\n$('#a')\n  .prop('href', 'https://baidu.com');\n\n// input\n$('#name').val();\t//获取值\n$('#name').val('fzf');\t//设置值\n// 集中于Input\n$('#name').focus();\n// 选中\n$('#name').select();\n// 不选\n$('#name').blur();\n// 触发\n$('#name').focus(\n  () => {\n    alert(\"Don't Touch me\")\n  }\n);\n// 提交表单\n$('#name').submit();\n```\n\n> 实战\n\n```js\n$('#input').focus(\n  () => {\n    alert(\"Don't Touch me\")\n  }\n);\n```\n\n## 获取URL参数\n\n```js\n// 获取url\nwindow.location.href\n// 解析url参数\n$.getUrlParam = function (name) {\n  var reg = new RegExp(\"(^|&)\" + name + \"=([^&]*)(&|$)\");\n  var r = window.location.search.substr(1).match(reg);\n  if (r != null) return unescape(r[2]); return null;\n}\n\nvar getname = $.getUrlParam('name');\n```\n\n## 事件\n\n```js\n// 判断checkbox是否选中\n$checkbox.is(':checked')\n// checkbox赋值\n$checkbox.attr(\"checked\",true)\n```\n\n"}}]);